```zig
fn generateHills(chunk: *Chunk) void {
    const minDistance = 20; // Decrease this value to make hills closer together
    const maxHeight = 50;   // Increase this value to make hills taller
    var x: i32 = -chunk.size / 2;
    while (x < chunk.size / 2) {
        var z: i32 = -chunk.size / 2;
        while (z < chunk.size / 2) {
            if (rand.int() % minDistance == 0) {
                const hillHeight = rand.intRangeAtMost(maxHeight);
                for (y: i32 = 0; y <= hillHeight; y += 1) {
                    chunk.setBlock(x, y, z, Block.HILL);
                }
            }
            z += 1;
        }
        x += 1;
    }
}
