const std = @import("std");
const cubyz = @import("cubyz");

pub fn loadTexture() !void {
    const allocator = cubyz.memory.allocator;
    const texture_path = "cubyz:cloth/black";
    var texture = try cubyz.graphics.Texture.load(allocator, texture_path);
    defer texture.destroy();

    // Apply the texture to a renderable object
    var renderable = cubyz.render.RenderableObject.init(allocator);
    defer renderable.deinit();
    renderable.setTexture(texture);
}
