```zig
const std = @import("std");
const json = std.json;

pub fn main() !void {
    const allocator = std.heap.page_allocator;
    defer allocator.deinit();

    const data = ".{\n    .blueprints = .{\n        .{.id = "cubyz:tree/oak/old_growth/branch/0"},\n        .{.id = "cubyz:tree/oak/old_growth/branch/1"},\n        .{.id = "cubyz:tree/oak/old_growth/branch/2"},\n        .{.id = "cubyz:tree/oak/old_growth/branch/3"},\n    },\n}";

    var parser = json.Parser(allocator).init(data);
    defer parser.deinit();

    const value = try parser.parse().value;
    defer value.destroy();

    const blueprints = value.get(.blueprints).toObjectMap();
    const firstBlueprintId = blueprints.get(@intCast(u32, 0)).?.get(.id).toString();

    std.debug.print("First branch blueprint ID: {s}\n", .{firstBlueprintId});
}
