const std = @import("std");

pub fn getBlueprintIDs(chunkFile: []const u8) ![]const []const u8 {
    var jsonParser = std.json.Parser(std.heap.page_allocator).init(chunkFile);
    defer jsonParser.deinit();

    const value = try jsonParser.parse().value;
    defer value.deinit();

    if (value.rootObject.get("blueprints") == null) {
        return error.NoBlueprintsFound;
    }

    var blueprintIDs: []const []const u8 = &[_][]const u8{};
    for (value.rootObject.get("blueprints").?.array.items) |item| {
        const idValue = item.object.get("id") orelse continue;
        const id = idValue.string.text();
        blueprintIDs = std.ArrayList([]const u8).init(std.heap.page_allocator).append(id) catch unreachable;
    }

    return blueprintIDs;
}

