const std = @import("std");

pub fn parseBlueprints(file_path: []const u8) ![]string {
    var allocator = std.heap.page_allocator;
    const file = try std.fs.openFileRead(file_path);
    defer file.close();

    const contents = try file.readAllAlloc(allocator, std.math.maxInt(u32));
    defer allocator.free(contents);

    // Assuming the JSON structure is known and valid
    var json_parser = std.json.Parser.init(allocator);
    defer json_parser.destroy();

    const value = try json_parser.parse(contents);
    defer value.deinit();

    const blueprints_array = value.root.get("blueprints").?.array;

    var result: []string = allocator.alloc(string, blueprints_array.len);
    defer allocator.free(result);

    for (0..blueprints_array.len) |i| {
        const blueprint_id = blueprints_array[i].get("id").?.string;
        result[i] = try std.mem.dup(allocator, u8, blueprint_id);
    }

    return result;
}
